import org.springframework.cloud.client.ServiceInstance;
import org.springframework.cloud.client.discovery.DiscoveryClient;
import org.springframework.web.bind.annotation.*;
import java.net.URI;
import java.util.*;
import java.util.stream.Collectors;
import org.springframework.stereotype.Component;

@RestController
@RequestMapping("/discovery")
public class ServiceDiscoveryController {
    private final DiscoveryClient discoveryClient;

    ServiceDiscoveryController(DiscoveryClient discoveryClient) {
        this.discoveryClient = discoveryClient;
    }

    @GetMapping("/services")
    public List<String> listServices() {
        return discoveryClient.getServices();
        // Returns: ["market-service", "order-service", "eureka-server"]
    }

    @GetMapping("/services/{name}")
    public List<String> getServiceInstances(@PathVariable String name) {
        return discoveryClient.getInstances(name).stream()
            .map(instance -> instance.getUri().toString())
            .collect(Collectors.toList());
        // Returns: ["http://10.0.1.45:8081", "http://10.0.1.67:8082"]
    }

    @GetMapping("/services/{name}/count")
    public Map<String, Object> getInstanceCount(@PathVariable String name) {
        int count = discoveryClient.getInstances(name).size();
        return Map.of("service", name, "instances", count);
    }
}

