import org.springframework.boot.actuate.health.*;
import org.springframework.stereotype.Component;
import org.springframework.beans.factory.annotation.Autowired;
import javax.sql.DataSource;
import java.sql.Connection;

// Custom health indicator:
@Component
public class OrderDatabaseHealthIndicator implements HealthIndicator {
    private final DataSource dataSource;
    OrderDatabaseHealthIndicator(DataSource ds) { dataSource = ds; }

    @Override
    public Health health() {
        try (Connection conn = dataSource.getConnection()) {
            conn.isValid(2);  // 2 second timeout
            return Health.up().withDetail("db", "Order database is reachable").build();
        } catch (Exception e) {
            return Health.down()
                .withDetail("db", "Order database unreachable: " + e.getMessage())
                .build();
        }
    }
}

