import org.springframework.cloud.client.*;
import org.springframework.cloud.client.discovery.DiscoveryClient;
import org.springframework.web.bind.annotation.*;
import org.springframework.http.*;
import java.util.*;
import java.util.stream.*;
import org.springframework.stereotype.Controller;

@RestController @RequestMapping("/admin/registry")
public class RegistryController {
    private final DiscoveryClient discoveryClient;
    RegistryController(DiscoveryClient dc) { discoveryClient = dc; }

    // All services and instance count:
    @GetMapping
    public Map<String, Object> getAllServices() {
        Map<String, Object> result = new LinkedHashMap<>();
        discoveryClient.getServices().forEach(svc -> {
            List<ServiceInstance> instances = discoveryClient.getInstances(svc);
            result.put(svc, Map.of(
                "count", instances.size(),
                "uris",  instances.stream().map(i -> i.getUri().toString()).toList()
            ));
        });
        return result;
    }

    // Detailed info for one service:
    @GetMapping("/{service}")
    public ResponseEntity<List<Map<String,Object>>> getServiceDetails(
            @PathVariable String service) {
        List<ServiceInstance> instances = discoveryClient.getInstances(service);
        if (instances.isEmpty()) return ResponseEntity.notFound().build();

        List<Map<String,Object>> details = instances.stream()
            .map(i -> Map.of(
                "instanceId", i.getInstanceId(),
                "host",       i.getHost(),
                "port",       i.getPort(),
                "uri",        i.getUri().toString(),
                "metadata",   i.getMetadata()
            ))
            .collect(Collectors.toList());
        return ResponseEntity.ok(details);
    }

    // Count UP instances (Eureka considers all registered instances UP):
    @GetMapping("/{service}/count")
    public Map<String,Object> getInstanceCount(@PathVariable String service) {
        int count = discoveryClient.getInstances(service).size();
        return Map.of("service", service, "upInstances", count);
    }
}

