import org.springframework.cloud.client.ServiceInstance;
import org.springframework.cloud.client.discovery.DiscoveryClient;
import org.springframework.stereotype.Component;
import org.springframework.beans.factory.annotation.Value;
import javax.annotation.PostConstruct;
import java.util.*;

@Component
public class VersionAwareRouter {
    private final DiscoveryClient discoveryClient;
    @Value("${app.preferred-version:2.0.1}")
    private String preferredVersion;

    VersionAwareRouter(DiscoveryClient dc) { discoveryClient = dc; }

    // Find instances of a service matching the preferred version:
    public Optional<ServiceInstance> findCompatibleInstance(String serviceName) {
        return discoveryClient.getInstances(serviceName).stream()
            .filter(instance -> preferredVersion.equals(
                instance.getMetadata().get("version")))
            .findFirst();  // pick first matching version
    }

    @PostConstruct
    public void logVersions() {
        discoveryClient.getServices().forEach(svc ->
            discoveryClient.getInstances(svc).forEach(instance ->
                System.out.printf("  %s @ %s  version=%s%n",
                    svc,
                    instance.getUri(),
                    instance.getMetadata().getOrDefault("version", "unknown"))
            )
        );
    }
}

