import org.springframework.stereotype.Service;
@Service class TradeService {
    private final MarketServiceClient marketClient;
    TradeService(MarketServiceClient mc) { marketClient=mc; }
    public String executeTrade(String userId, String symbol, int qty) {
        var quote = marketClient.getQuote(symbol);
        if(!quote.tradeable()) throw new IllegalStateException(symbol+" not tradeable");
        return "TRD-"+symbol+"-"+qty+"@"+quote.price();
    }
}
